parameters.jsCode:
const response = $input.first().json.output || $input.first().json.text || '';
if (!response || !response.trim()) {
  throw new Error('No response received from Claude KW Expansion');
}
let keywords;
try {
  keywords = JSON.parse(response);
} catch(e) {
  const match = response.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) {
    try {
      keywords = JSON.parse(match[1]);
    } catch(e2) {
      throw new Error('Could not parse keywords JSON: ' + e2.message);
    }
  } else {
    throw new Error('Could not find JSON in response');
  }
}
if (!Array.isArray(keywords)) keywords = keywords.keywords || [];
if (keywords.length === 0) throw new Error('No keywords generated');
return keywords.map(k => ({ json: k }));

const results = $input.first().json.web?.results || [];
if (results.length === 0) {
  throw new Error('No search results returned from Brave');
}
const urls = results
  .filter(r => r.url && !r.url.match(/youtube|twitter|facebook|instagram|linkedin/i))
  .slice(0, 10)
  .map((r, i) => ({ url: r.url, title: r.title || '', position: i + 1 }));
if (urls.length === 0) {
  throw new Error('No valid URLs found after filtering social media sites');
}
return urls.map(u => ({ json: u }));

const html = $input.first().json.data || $input.first().json.body || '';
if (!html || !html.trim()) {
  return [{ json: { clean_text: '', headings: [], word_count: 0, image_count: 0, url: $input.first().json.url || '' } }];
}
let text = html.replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<style[\s\S]*?<\/style>/gi, '');
const headings = [];
const headingRegex = /<(h[1-3])[^>]*>([\s\S]*?)<\/\1>/gi;
let match;
while ((match = headingRegex.exec(html)) !== null) {
  headings.push({ level: match[1], text: match[2].replace(/<[^>]+>/g, '').trim() });
}
const imageCount = (html.match(/<img/gi) || []).length;
text = text.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const wordCount = text.split(/\s+/).filter(w => w).length;
return [{
  json: {
    clean_text: text.substring(0, 15000),
    headings, word_count: wordCount, image_count: imageCount,
    url: $input.first().json.url || ''
  }
}];

const items = $input.all();
if (items.length === 0) {
  return [{ json: { error: 'No pages to process' } }];
}
return items.slice(0, 5);

const data = $input.first().json.data || [];
const pageCount = Array.isArray(data) ? data.length : 1;
let confidence = 'high';
if (pageCount < 5) confidence = 'medium';
if (pageCount < 3) confidence = 'low';
return [{ json: { ...($input.first().json), confidence, page_count: pageCount } }];

