const response = $input.first().json.output || $input.first().json.text || '';
if (!response || !response.trim()) {
  return [{ json: { title: 'Untitled', meta_description: '', slug: 'untitled', key_takeaways: [] } }];
}
let meta;
try {
  meta = JSON.parse(response);
} catch(e) {
  const match = response.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) {
    try {
      meta = JSON.parse(match[1]);
    } catch(e2) {
      meta = { title: 'Untitled', meta_description: '', slug: 'untitled', key_takeaways: [] };
    }
  } else {
    meta = { title: 'Untitled', meta_description: '', slug: 'untitled', key_takeaways: [] };
  }
}
// Ensure all required fields
meta.title = meta.title || 'Untitled';
meta.meta_description = meta.meta_description || '';
meta.slug = meta.slug || 'untitled';
meta.key_takeaways = meta.key_takeaways || [];
return [{ json: meta }];

const article = $input.first().json.html_content || '';
if (!article || !article.trim()) {
  return [{ json: { ...$input.first().json, nlp_score: 0, word_count: 0, missing_terms: [] } }];
}
const nlpTermsRaw = $('Set Writer Context').item.json.nlp_terms || '[]';
const nlpTerms = typeof nlpTermsRaw === 'string' ? JSON.parse(nlpTermsRaw) : nlpTermsRaw;
const articleLower = article.toLowerCase();
let found = 0;
const missing = [];
for (const term of nlpTerms) {
  const t = typeof term === 'string' ? term : term.term || '';
  if (!t) continue;
  if (articleLower.includes(t.toLowerCase())) { found++; } else { missing.push(t); }
}
const score = nlpTerms.length > 0 ? Math.round((found / nlpTerms.length) * 100) : 0;
const wordCount = article.replace(/<[^>]+>/g, ' ').split(/\s+/).filter(w => w).length;
return [{ json: { ...$input.first().json, nlp_score: score, word_count: wordCount, missing_terms: missing } }];

const article = $input.first().json.fields || $input.first().json;
const slug = article.slug || 'untitled';
const doc = {
  mutations: [{
    createOrReplace: {
      _type: 'post',
      _id: 'v2-' + slug,
      title: article.title || 'Untitled',
      slug: { _type: 'slug', current: slug },
      body: article.html_content || '',
      metaDescription: article.meta_description || '',
      publishedAt: new Date().toISOString()
    }
  }]
};
return [{ json: doc }];

